INSERT INTO doctor (doctor_code, doctor_name, department_code, title, specialty, doctor_des, doctor_image) VALUES ('DOC_DEPT016_4', 'зҪ—йқҷ', 'DEPT016', 'дё»жІ»еҢ»еёҲ', 'жіҢе°ҝзі»иӮҝзҳӨж №жІ?, 'зҪ—йқҷдё»жІ»еҢ»еёҲпјҢд»ҺдәӢжіҢе°ҝеӨ–з§‘дёҙеәҠе·ҘдҪ?0е№ҙпјҢдё“дёҡдёҘи°ЁгҖӮд»–дё“жіЁдәҺжіҢе°ҝзі»иӮҝзҳӨж №жІ»зҡ„иҜҠз–—пјҢе·ІжҲҗеҠҹжІ»ж„Ҳж•°еҚғдҫӢзӣёе…іжӮЈиҖ…гҖ?, 'doc_DOC_DEPT016_4.png');
