INSERT INTO doctor (doctor_code, doctor_name, department_code, title, specialty, doctor_des, doctor_image) VALUES ('DOC_DEPT018_3', 'еј йқҷ', 'DEPT018', 'еүҜдё»д»»еҢ»её?, 'йҡҫжІ»жҖ§еӨұзң з®Ўзҗ?, 'еј йқҷеүҜдё»д»»еҢ»еёҲпјҢд»ҺдәӢзІҫзҘһеҝғзҗҶз§‘дёҙеәҠе·ҘдҪ?1е№ҙпјҢеҢ»жңҜзІҫж№ӣгҖӮд»–ж“…й•ҝйҡҫжІ»жҖ§еӨұзң з®ЎзҗҶзҡ„иҜҠз–—пјҢе·ІжҲҗеҠҹжІ»ж„Ҳж•°еҚғдҫӢзӣёе…іжӮЈиҖ…гҖ?, 'doc_DOC_DEPT018_3.png');
